export function getAreas(onsCode: string): ConstituencyAreas | undefined {
  return CONSTITUENCY_AREAS[onsCode];
}

export function getWardCodes(onsCode: string): string[] {
  const a = CONSTITUENCY_AREAS[onsCode];
  return a ? a.wards.map(w => w.code) : [];
}

export function getLadCodes(onsCode: string): string[] {
  const a = CONSTITUENCY_AREAS[onsCode];
  return a ? a.lads.map(l => l.code) : [];
}

export function getNomisCodes(onsCode: string): number[] {
  const a = CONSTITUENCY_AREAS[onsCode];
  return a ? a.lads.filter(l => l.nomisCode).map(l => l.nomisCode as number) : [];
}